/**
 * Conway's transition rule: a cell is live next generation when it has
 * exactly 3 live neighbors (birth), or it is currently alive and has
 * exactly 2 live neighbors (survival).
 */
const willLive = (isAlive: boolean, liveNeighbors: number): boolean =>
  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);

export function nextGeneration(cells: Cell[]): Cell[] {
  const living = new Set(cells.map(toKey));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = toKey([x + dx, y + dy]);
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  for (const [key, liveNeighbors] of neighborCounts) {
    if (willLive(living.has(key), liveNeighbors)) {
      next.push(fromKey(key));
    }
  }
  return next;
}

